const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const FIRST_INSURANCE_RATE = 0.1;
const PROCESSING_FEE = 5;

export function processScenario(scenario: { steps: { items?: { type: string }[] }[] }): { results: unknown[] } {
  const items = scenario.steps[0].items ?? [];
  const basePremium = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const premium = Math.ceil(basePremium + basePremium * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
  return { results: [{ premium }] };
}

