import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("should return 5G for empty item list (processing fee only)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      });
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("should return 115G for a single sword (100G base + 10G first insurance + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should return correct base premium for each main item type", () => {
      const quote = (type: string) =>
        processScenario({
          customer: { yearsWithMHPCO: 0 },
          steps: [
            {
              op: "quote" as const,
              items: [{ type, material: "steel", enchantment: 0, cursed: false }],
            },
          ],
        }).results[0];

      expect(quote("amulet")).toEqual({ premium: 71 });
      expect(quote("staff")).toEqual({ premium: 93 });
      expect(quote("potion")).toEqual({ premium: 49 });
    });
    it("should sum base premiums for multiple items plus fee", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 181 });
    });
  });

  describe("Quote - components", () => {
    it("should charge 25G base premium per component", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }],
          },
        ],
      });
      // 25G base + 2.5G first insurance (10%) = 27.5 → ceil = 28 + 5 fee = 33
      expect(result.results[0]).toEqual({ premium: 33 });
    });
    it("should charge 60G for a block of exactly 3 alike components", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
          },
        ],
      });
      // 60G block base + 6G first insurance (10%) = 66 → ceil = 66 + 5 fee = 71
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it.todo("should not apply block when count is not exactly 3");
    it.todo("should treat different component types separately for blocks");
  });

  describe("Quote - item-specific modifiers", () => {
    it.todo("should add 50% cursed surcharge on the cursed item base premium");
    it.todo("should add 30% surcharge for enchantment level >= 5");
    it.todo("should scope item-specific modifiers to affected item only in multi-item policy");
  });

  describe("Quote - policy-wide modifiers", () => {
    it.todo("should apply 20% loyalty discount for >= 2 years with MHPCO");
    it.todo("should apply 10% first insurance surcharge");
    it.todo("should apply 15% follow-up discount on second+ quote");
  });

  describe("Quote - integration", () => {
    it.todo("should compute 165G for newcomer with cursed sword");
    it.todo("should compute 160G for long-standing customer second contract with cursed high-enchantment sword");
  });

  describe("Quote - rounding", () => {
    it.todo("should round premiums up in MHPCO favor");
  });

  describe("Claim - reimbursement", () => {
    it.todo("should fully reimburse minus 100G deductible for standard items");
    it.todo("should reimburse at 50% then deductible for enchantment >= 8");
    it.todo("should fully reimburse then deductible for dragon-material items");
    it.todo("should apply 50% when both dragon material and enchantment >= 8");
  });

  describe("Claim - cap and successive claims", () => {
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reduce remaining cap across successive claims");
    it.todo("should apply deductible per damaged item in multi-damage event");
  });

  describe("Claim - rounding", () => {
    it.todo("should round payouts down in MHPCO favor");
  });

  describe("Error handling", () => {
    it.todo("should reject unknown item types");
    it.todo("should reject claim for item not in policy");
    it.todo("should reject negative damage amounts");
    it.todo("should reject excess damage entries beyond policy coverage");
  });
});

