const MAIN_ITEM_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const FIRST_INSURANCE_RATE = 0.1;
const PROCESSING_FEE = 5;

function componentPremium(items: { type: string }[]): number {
  const counts = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    }
  }
  let total = 0;
  for (const [, count] of counts) {
    total += count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
  }
  return total;
}

function computeBasePremium(items: { type: string }[]): number {
  const mainItemTotal = items
    .filter((item) => !COMPONENT_TYPES.has(item.type))
    .reduce((sum, item) => sum + MAIN_ITEM_PREMIUMS[item.type], 0);
  return mainItemTotal + componentPremium(items);
}

export function processScenario(scenario: { steps: { items?: { type: string }[] }[] }): { results: unknown[] } {
  const items = scenario.steps[0].items ?? [];
  const basePremium = computeBasePremium(items);
  const premium = Math.ceil(basePremium + basePremium * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
  return { results: [{ premium }] };
}

