  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const CURSED_SURCHARGE_RATE = 0.5;

const FIRST_INSURANCE_RATE = 0.1;
const PROCESSING_FEE = 5;

interface Item {
  type: string;
  cursed?: boolean;
}

function componentPremium(items: Item[]): number {
  const counts = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    }
  }
  let total = 0;
  for (const [, count] of counts) {
    total += count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
  }
  return total;
}

function itemBasePremium(item: Item): number {
  if (COMPONENT_TYPES.has(item.type)) return COMPONENT_PREMIUM;
  return MAIN_ITEM_PREMIUMS[item.type];
}

function computeBasePremium(items: Item[]): number {
  const mainItemTotal = items
    .filter((item) => !COMPONENT_TYPES.has(item.type))
    .reduce((sum, item) => sum + MAIN_ITEM_PREMIUMS[item.type], 0);
  return mainItemTotal + componentPremium(items);
}

function computeItemSurcharges(items: Item[]): number {
  let surcharges = 0;
  for (const item of items) {
    const base = itemBasePremium(item);
    if (item.cursed) {
      surcharges += base * CURSED_SURCHARGE_RATE;
    }
  }
  return surcharges;
}

export function processScenario(scenario: { steps: { items?: Item[] }[] }): { results: unknown[] } {
  const items = scenario.steps[0].items ?? [];
  const basePremium = computeBasePremium(items);
  const itemSurcharges = computeItemSurcharges(items);
  const premium = Math.ceil(basePremium + itemSurcharges + basePremium * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
  return { results: [{ premium }] };
}

