    }
  }
  let total = 0;
  for (const [, count] of counts) {
    total += count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
  }
  return total;
}

function itemBasePremium(item: Item): number {
  if (isComponent(item)) return COMPONENT_PREMIUM;
