      const basePremium = computeBasePremium(items);
      const itemSurcharges = computeItemSurcharges(items);

      let policyModifiers = basePremium * FIRST_INSURANCE_RATE;
      if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD) {
        policyModifiers -= basePremium * LOYALTY_DISCOUNT_RATE;
      }
      if (quoteCount > 1) {
        policyModifiers -= basePremium * FOLLOW_UP_DISCOUNT_RATE;
      }

      const premium = Math.ceil(basePremium + itemSurcharges + policyModifiers) + PROCESSING_FEE;
      results.push({ premium });
    }
  }

  return { results };
}

