1	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	};
7	
8	const COMPONENT_PREMIUM = 25;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
12	
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
16	
17	const LOYALTY_THRESHOLD = 2;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const FIRST_INSURANCE_RATE = 0.1;
20	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
21	const PROCESSING_FEE = 5;
22	
23	interface Item {
24	  type: string;
25	  cursed?: boolean;
26	  enchantment?: number;
27	}
28	
29	interface Scenario {
30	  customer: { yearsWithMHPCO: number };
31	  steps: { op: string; items?: Item[] }[];
32	}
33	
34	function isComponent(item: Item): boolean {
35	  return COMPONENT_TYPES.has(item.type);
36	}
37	
38	function componentPremium(items: Item[]): number {
39	  const counts = new Map<string, number>();
40	  for (const item of items) {
41	    if (isComponent(item)) {
42	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
43	    }
44	  }
45	  let total = 0;
46	  for (const [, count] of counts) {
47	    total += count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
48	  }
49	  return total;
50	}
51	
52	function itemBasePremium(item: Item): number {
53	  if (isComponent(item)) return COMPONENT_PREMIUM;
54	  return MAIN_ITEM_PREMIUMS[item.type];
55	}
56	
57	function computeBasePremium(items: Item[]): number {
58	  const mainItemTotal = items
59	    .filter((item) => !isComponent(item))
60	    .reduce((sum, item) => sum + itemBasePremium(item), 0);
61	  return mainItemTotal + componentPremium(items);
62	}
63	
64	function computeItemSurcharges(items: Item[]): number {
65	  let surcharges = 0;
66	  for (const item of items) {
67	    const base = itemBasePremium(item);
68	    if (item.cursed) {
69	      surcharges += base * CURSED_SURCHARGE_RATE;
70	    }
71	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
72	      surcharges += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
73	    }
74	  }
75	  return surcharges;
76	}
77	
78	function computePolicyModifiers(basePremium: number, yearsWithMHPCO: number, isFollowUp: boolean): number {
79	  let modifiers = basePremium * FIRST_INSURANCE_RATE;
80	  if (yearsWithMHPCO >= LOYALTY_THRESHOLD) {
81	    modifiers -= basePremium * LOYALTY_DISCOUNT_RATE;
82	  }
83	  if (isFollowUp) {
84	    modifiers -= basePremium * FOLLOW_UP_DISCOUNT_RATE;
85	  }
86	  return modifiers;
87	}
88	
89	export function processScenario(scenario: Scenario): { results: unknown[] } {
90	  const results: unknown[] = [];
91	  let quoteCount = 0;
92	
93	  for (const step of scenario.steps) {
94	    if (step.op === "quote") {
95	      quoteCount++;
96	      const items = step.items ?? [];
97	      const basePremium = computeBasePremium(items);
98	      const itemSurcharges = computeItemSurcharges(items);
99	      const policyModifiers = computePolicyModifiers(basePremium, scenario.customer.yearsWithMHPCO, quoteCount > 1);
100	
101	      const premium = Math.ceil(basePremium + itemSurcharges + policyModifiers) + PROCESSING_FEE;
102	      results.push({ premium });
103	    }
