export function processScenario(scenario: Scenario): { results: unknown[] } {
  const results: unknown[] = [];
  let quoteCount = 0;
  const policies = new Map<number, { items: Item[]; remainingCap: number }>();

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      quoteCount++;
      const items = step.items ?? [];
      const basePremium = computeBasePremium(items);
      const itemSurcharges = computeItemSurcharges(items);
      const policyModifiers = computePolicyModifiers(basePremium, scenario.customer.yearsWithMHPCO, quoteCount > 1);

      const premium = Math.ceil(basePremium + itemSurcharges + policyModifiers) + PROCESSING_FEE;
      const insuranceSum = computeInsuranceSum(items);
      policies.set(i, { items, remainingCap: insuranceSum * CAP_MULTIPLIER });
      results.push({ premium });
    } else if (step.op === "claim") {
      const policy = policies.get(step.policy!)!;
      let totalPayout = 0;

      for (const damage of step.incident!.damages) {
        const payout = damage.amount - DEDUCTIBLE;
        totalPayout += payout;
      }

      totalPayout = Math.min(totalPayout, policy.remainingCap);
      policy.remainingCap -= totalPayout;
      results.push({ payout: Math.floor(totalPayout), remainingCap: policy.remainingCap });
    }
  }

  return { results };
}

